/**
 * Retorna N questões aleatórias embaralhadas de uma matéria
 * A resposta correta aparece em posição aleatória (já está nos opts embaralhados)
 */
export function getQuestoes(area, n = 3) {
  const banco = BANCO_QUESTOES[area] || BANCO_QUESTOES.civil;
  const shuffled = [...banco].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, n).map(q => {
    // Embaralhar opções mantendo rastreio da correta
    const indexed = q.opts.map((o, i) => ({ texto: o, original: i }));
    const shuffledOpts = indexed.sort(() => Math.random() - 0.5);
    const novoC = shuffledOpts.findIndex(o => o.original === q.c);
    return {
      q:    q.q,
      opts: shuffledOpts.map(o => o.texto),
      c:    novoC,
      e:    q.e,
    };
  });
}
